mapper.select:
SELECT ID, USING_DEPT_ID, USING_DEPT_NAME, EQUIP_TYPE_ID, EQUIP_ID, EQUIP_NAME, APP_NUMBER, APP_TYPE, APP_CONTENT, MAINTENANCE_UNIT_ID, MAINTENANCE_UNIT_NAME, BUDGET_AMOUNT, REMARK, CREATED_USER, CREATED_TIME, UPDATE_USER, UPDATE_TIME FROM E_IC_MAINT_PROJ_APPLY WHERE 1 = 1
and USING_DEPT_NAME like #{usingDeptName}
and EQUIP_NAME like #{equipName}
order by CREATED_TIME DESC
